import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read the entire line including spaces

        int maxLength = 10; // Maximum length for the buffer
        char[] buffer = new char[maxLength];

        // Copy user input into the buffer with proper bounds checking
        int length = Math.min(userInput.length(), maxLength); // Limit length to prevent overflow
        userInput.getChars(0, length, buffer, 0);

        System.out.println("User input stored securely!");
    }
}

